/**
 * Public types for the XMem TypeScript SDK.
 */
export interface APIEnvelope<T = Record<string, unknown>> {
    status: "ok" | "error";
    data?: T;
    error?: string;
    request_id?: string;
    elapsed_ms?: number;
}
export interface HealthStatus {
    status: string;
    pipelines_ready: boolean;
    version: string;
    uptime_seconds?: number;
    error?: string;
}
export interface IngestParams {
    user_query: string;
    user_id: string;
    agent_response?: string;
    session_datetime?: string;
    image_url?: string;
}
export interface OperationDetail {
    type: string;
    content: string;
    reason: string;
}
export interface WeaverSummary {
    succeeded: number;
    skipped: number;
    failed: number;
}
export interface DomainResult {
    confidence: number;
    operations: OperationDetail[];
    weaver?: WeaverSummary;
}
export interface IngestResult {
    model: string;
    classification: unknown[];
    profile?: DomainResult;
    temporal?: DomainResult;
    summary?: DomainResult;
    image?: DomainResult;
    request_id?: string;
    elapsed_ms?: number;
}
export interface RetrieveParams {
    query: string;
    user_id: string;
    top_k?: number;
}
export interface SourceRecord {
    domain: string;
    content: string;
    score: number;
    metadata: Record<string, unknown>;
}
export interface RetrieveResult {
    model: string;
    answer: string;
    sources: SourceRecord[];
    confidence: number;
    request_id?: string;
    elapsed_ms?: number;
}
export interface SearchParams {
    query: string;
    user_id: string;
    domains?: string[];
    top_k?: number;
}
export interface SearchResult {
    results: SourceRecord[];
    total: number;
    request_id?: string;
    elapsed_ms?: number;
}
